def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity * 1.2:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.25:
            score = (1 - ratio)**4 + np.sin(ratio * 2 * np.pi) * 0.5
        elif 0.25 <= ratio < 0.5:
            score = np.log1p(ratio * 3) * 4 - np.sqrt(ratio) * 1.2
        elif 0.5 <= ratio < 0.75:
            score = 1 / (1 + np.exp(-20 * (ratio - 0.6))) + np.cos(ratio * 7) * 0.8
        elif 0.75 <= ratio < 0.95:
            score = np.tanh(15 * (ratio - 0.8)) + 0.7 + np.sin(ratio * 10) * 0.3
        else:
            score = np.tanh(20 * (ratio - 0.95)) + 1.0
        penalty = 0
        for j in range(1, 8):
            mod_val = ((item * j * 1.1) % capacity)
            frac = mod_val / (capacity * j)
            if frac < 0.05:
                penalty += frac * 3
            elif 0.05 <= frac < 0.15:
                penalty += frac * 2
            elif 0.15 <= frac < 0.35:
                penalty += frac * 1.2
            else:
                penalty += frac / (j + 2)
        extra_penalty = 0
        for k in range(1, 5):
            if ratio > 0.4 * k:
                extra_penalty += np.exp(-k * ratio) * k * (0.9 + 0.1 * k)
            else:
                extra_penalty += np.log1p(k * ratio * 2 + 0.5) / (k + 0.5)
        adjustment = 0
        if capacity % 3 == 0:
            adjustment = np.sin(ratio * capacity) * 0.5
        elif capacity % 5 == 0:
            adjustment = np.cos(ratio * capacity / 2) * 0.4
        else:
            adjustment = np.tanh(ratio * 3) * 0.3
        if capacity % 2 == 0:
            priorities[i] = score + penalty + extra_penalty + adjustment
        else:
            priorities[i] = score + penalty * 1.7 + extra_penalty * 0.9 + adjustment * 0.8
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
